VALUES
  ('diplomatic-36ccc47a-moex-00070', 'diplomatic-36ccc47a', 'diplomatic-36ccc47a-moex-114-c655adf3', 'sub-diplomatic-36ccc47a-04', NULL, 'single_choice', '依臺灣地區與大陸地區人民關係條例第 65 條第 1 款規定：「臺灣地區人民收養大陸地區人民為養子 女，……有下列情形之一者，法院亦應不予認可：一、已有子女或養子女者。」依司法院大法官解釋， 此一規定是否合憲？', '["合憲，因為憲法並未保障收養自由，收養對象之規定純屬立法裁量", "違憲，因臺灣地區人民收養其配偶之大陸地區子女，法院亦應不予認可部分，有違憲法第22條保 障收養自由之意旨", "合憲，因本法涉及兩岸關係，為司法不應解釋之政治問題", "違憲，因臺灣地區人民收養其他國家、地區人民為養子女，並無此等限制，系爭規定違反憲法第7 條平等權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:24+00:00", "source_pdf_sha1": "74e57a3571a6", "answer_pdf_sha1": "b3f1a7073313", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-越南文組"}'::jsonb, NULL),
