  ('diplomatic-36ccc47a-moex-00072', 'diplomatic-36ccc47a', 'diplomatic-36ccc47a-moex-114-c655adf3', 'sub-diplomatic-36ccc47a-04', NULL, 'single_choice', '依立法院的組織與運作之規定，下列敘述何者錯誤？', '["立法院設院長、副院長各一人，由立法委員互選產生", "立法院院長、副院長不得擔任政黨職務，應本公平中立原則行使職權，維持立法院秩序，處理議事", "立法院會議，應公開舉行，不得開秘密會議", "立法院臨時會，以決議召集臨時會之特定事項為限"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:24+00:00", "source_pdf_sha1": "74e57a3571a6", "answer_pdf_sha1": "b3f1a7073313", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-越南文組"}'::jsonb, NULL),
  ('diplomatic-36ccc47a-moex-00073', 'diplomatic-36ccc47a', 'diplomatic-36ccc47a-moex-114-c655adf3', 'sub-diplomatic-36ccc47a-04', NULL, 'single_choice', '有關中央與地方立法權限之規定，下列敘述何者正確？', '["警察制度事項，由中央立法並執行之", "行政區劃事項，由中央立法並執行之", "司法制度事項，由中央立法並執行之，或交由省縣執行之", "度量衡事項，由中央立法並執行之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:24+00:00", "source_pdf_sha1": "74e57a3571a6", "answer_pdf_sha1": "b3f1a7073313", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-越南文組"}'::jsonb, NULL),
  ('diplomatic-36ccc47a-moex-00074', 'diplomatic-36ccc47a', 'diplomatic-36ccc47a-moex-114-c655adf3', 'sub-diplomatic-36ccc47a-04', NULL, 'single_choice', '在中國的打壓下為持續拓展國際關係，我國政府展開一連串務實外交計畫及其他非正式外交。請依據 我國實際的參與情況，判斷下列何者最為正確？', '["為了保留聯合國席位，改以中華臺北為名", "透過民間組織來參與國際奧林匹克委員會", "世界貿易組織將我國稱為臺澎金馬個別關稅領域", "以中國臺灣的名義成功加入了世界衛生組織"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:24+00:00", "source_pdf_sha1": "74e57a3571a6", "answer_pdf_sha1": "b3f1a7073313", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-越南文組"}'::jsonb, NULL),
  ('diplomatic-36ccc47a-moex-00075', 'diplomatic-36ccc47a', 'diplomatic-36ccc47a-moex-114-c655adf3', 'sub-diplomatic-36ccc47a-04', NULL, 'single_choice', '強韌的軍事實力，是確保臺灣擁有獨立主權的基石。美國現今授與臺灣「防禦性質的武器」，並「維 持能力，以抵抗任何訴諸武力」。其最重要的法源基礎為何？', '["臺灣關係法", "中美共同防禦條約", "臺灣友邦國際保護及加強倡議法", "臺灣安全加強法"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:24+00:00", "source_pdf_sha1": "74e57a3571a6", "answer_pdf_sha1": "b3f1a7073313", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-越南文組"}'::jsonb, NULL),
